import pandas as pd
import numpy as np
import re

# Reuse staged upstream outputs only.
_candidate_metric_frames_for_final_outputs = [
    station17_20250802_full_day_pollution_metrics_for_spatial_retry,
    station17_20250802_full_day_pollution_metrics_for_spatial,
    station17_20250802_rush_pollution_metrics_df,
]
_candidate_metric_dicts_for_final_outputs = [
    station17_20250802_rush_pollution_metrics,
]

def _norm(s):
    return re.sub(r"[^a-z0-9]+", "", str(s).lower())

def _is_mean_pm25(s):
    n = _norm(s)
    return ("pm25" in n or "pm2_5" in str(s).lower()) and ("mean" in n or "avg" in n or "average" in n)

def _is_max_pm25(s):
    n = _norm(s)
    return ("pm25" in n or "pm2_5" in str(s).lower()) and ("max" in n or "peak" in n)

def _is_mean_aqhi(s):
    n = _norm(s)
    return "aqhi" in n and ("mean" in n or "avg" in n or "average" in n)

def _is_max_aqhi(s):
    n = _norm(s)
    return "aqhi" in n and ("max" in n or "peak" in n)

def _extract_from_wide_df(df, pred):
    if not isinstance(df, pd.DataFrame) or df.empty:
        return None
    for c in df.columns:
        if pred(c):
            vals = pd.to_numeric(df[c], errors="coerce").dropna()
            if not vals.empty:
                return float(vals.iloc[0])
    return None

def _extract_from_long_df(df, pred):
    if not isinstance(df, pd.DataFrame) or df.empty:
        return None
    metric_cols = [c for c in df.columns if _norm(c) in ("metric", "name", "variable", "stat", "statistic", "measure")]
    value_cols = [c for c in df.columns if _norm(c) in ("value", "val", "result")]
    if not metric_cols:
        metric_cols = [c for c in df.columns if df[c].dtype == "object"]
    if not value_cols:
        value_cols = [c for c in df.columns if pd.api.types.is_numeric_dtype(df[c])]
    for mc in metric_cols:
        mask = df[mc].astype(str).map(pred)
        if mask.any():
            for vc in value_cols:
                vals = pd.to_numeric(df.loc[mask, vc], errors="coerce").dropna()
                if not vals.empty:
                    return float(vals.iloc[0])
    return None

def _extract_from_dict(d, pred):
    if not isinstance(d, dict):
        return None
    for k, v in d.items():
        if pred(k):
            try:
                if pd.notna(v):
                    return float(v)
            except Exception:
                pass
    return None

def _get_metric(pred):
    for d in _candidate_metric_dicts_for_final_outputs:
        v = _extract_from_dict(d, pred)
        if v is not None:
            return v
    for df in _candidate_metric_frames_for_final_outputs:
        v = _extract_from_wide_df(df, pred)
        if v is not None:
            return v
        v = _extract_from_long_df(df, pred)
        if v is not None:
            return v
    raise ValueError("Required staged metric could not be extracted from available upstream variables.")

mean_pm2_5 = _get_metric(_is_mean_pm25)
max_pm2_5 = _get_metric(_is_max_pm25)
mean_aqhi = _get_metric(_is_mean_aqhi)
max_aqhi = _get_metric(_is_max_aqhi)

print("mean_pm2_5 =", mean_pm2_5)
print("max_pm2_5 =", max_pm2_5)
print("mean_aqhi =", mean_aqhi)
print("max_aqhi =", max_aqhi)
